`,kt(t.p,{children:"We introduce Persona-E², a human-grounded dataset for personality-shaped emotion analysis, and demonstrate that trait-aware modeling—particularly using the Big Five—helps LLMs mitigate ``personality illusion'' in simulating reader appraisals."}),`
`,kt(t.h1,{children:"Abstract"}),`
`,kt(t.p,{children:"Persona-E² is a large-scale dataset designed to explore the complex interplay between persona, events, and emotional responses. Understanding how individual personalities influence emotional reactions to various life events, news, and social media content is crucial for developing more empathetic and human-like AI systems. This dataset provides expert-annotated events coupled with detailed persona profiles and their corresponding emotional states, enabling research into persona-driven emotion prediction and empathetic response generation. Our analysis reveals that persona information significantly enhances the accuracy of emotion prediction models across diverse scenarios."})]})}function Qhe(e={}){const{wrapper:t}=e.components||{};return t?kt(t,{...e,children:kt(bk,{...e})}):bk(e)}const Jhe={__name:"Abstract",setup(e){return(t,n)=>{const r=$e("el-divider"),a=$e("el-col"),o=$e("el-row");return P(),V("div",null,[z(r),z(o,{justify:"center"},{default:U(()=>[z(a,{xs:24,sm:20,md:16,lg:14,xl:14},{default:U(()=>[z(v(Qhe))]),_:1})]),_:1})])}}};function _k(e){const t={h1:"h1",h2:"h2",h3:"h3",p:"p",strong:"strong",...e.components},{DomainPieChart:n,EmoBarChart:r,RQ2_Top1_2Acc:a,RQ3_Metric:o,RQ3_Winrate:i,SDS_Distribution:s}=t;return n||Ul("DomainPieChart",!0),r||Ul("EmoBarChart",!0),a||Ul("RQ2_Top1_2Acc",!0),o||Ul("RQ3_Metric",!0),i||Ul("RQ3_Winrate",!0),s||Ul("SDS_Distribution",!0),kt(Ve,{children:[kt(t.h1,{children:"Introduction"}),`
`,kt(t.p,{children:"The study of affective appraisal of events has long been central to affective computing and cognitive psychology. While appraisal theories suggest that emotions emerge through individualized appraisals shaped by goals and dispositions, NLP research has largely focused on writer-expressed sentiments and reader-based unified emotional labels. This focus overlooks reader-based nuanced perception, which is critical for applications, including empathetic agents, mental health support, and personalized AI assistants."}),`
`,kt(t.p,{children:["To address the gap, we introduce ",kt(t.strong,{children:"Persona-E²"})," (Persona-Event2Emotion), a novel dataset that incorporates MBTI and Big Five traits into reader-based emotion labeling."]}),`
